	// all DailyData at the end of the forloop
	for _, raw := range rawDatas {
		day := raw.Date.Truncate(24 * time.Hour)
		current := dbDatas[day.String()]

		var isNew bool // Tell if the current DailyData juste have been created

		if current == nil {
			current = &DailyData{
				SensorID: raw.SensorID,
				Date:     day,
			}
			isNew = true
			dbDatas[day.String()] = current
			dates = append(dates, day)
			sortDates(dates)
		}

		if raw.Value != nil {
			current.AddUpdate(raw.Value, nil, nil, nil, raw.UnitPrice, raw.Date.Time, raw.Threshold, raw.Coef)

			s.datas.Store(current)
			continue
		} else if raw.Index != nil {
			var lastIdx *float64
			prevDate, nextDate := prevNextDates(dates, day)
			if isNew {
				if prevDate != nil {
					prevData := dbDatas[prevDate.String()]

					if prevData != nil {
						lastIdx = prevData.Index
					}
				}

				current.AddUpdate(nil, raw.Index, lastIdx, raw.Factor, raw.UnitPrice, raw.Date.Time, raw.Threshold, raw.Coef)
				s.datas.Store(current)

				if nextDate != nil {
					nextData := dbDatas[nextDate.String()]
