			if err != nil {
				return err
			}

			s.datas.Store(current)
		} else {
			return fmt.Errorf("there is no value or index for sensor %s for date %v", raw.SensorID, raw.Date.Time)
		}
	}

	return nil
}

// Recompute the values based on index if needed for the sensor data just after the given period
func (s *service) RecomputeNextValue(sensorID string, start, end time.Time) error {
	// Get data from start to end
	datas := s.datas.FindForDates(SensorParams{SensorID: &sensorID}, start, end)

	if len(datas) == 0 {
		return fmt.Errorf("no data found for sensor %s between %v and %v", sensorID, start, end)
	}

	// Get the last data before the end date
	lastDatum, dt := datas[len(datas)-1].GetLastDatumDTBefore(end.Hour(), end.Minute(), end.Second())

	if lastDatum == nil && len(datas) > 1 {
		lastDatum, dt = datas[len(datas)-2].GetLastDatumDTBefore(end.Hour(), end.Minute(), end.Second())
	}

	if lastDatum == nil {
		return fmt.Errorf("no data found before %v", end)
	}

	// Find next data after the end date to recompute values based on index if needed
	nextDatum, dt := datas[len(datas)-1].GetFirstDatumDTAfter(end.Hour(), end.Minute(), end.Second())

	if nextDatum != nil {

		// If the next datum has no index, no need to recompute value
		if nextDatum.Index == nil {
			return nil
		}

		// If the next datum has an index, we need to recompute the value
		err := datas[len(datas)-1].AddUpdate(nil, nextDatum.Index, lastDatum.Index, nextDatum.Coef, nextDatum.UnitPrice, dt, nextDatum.Threshold, nextDatum.Coef)

		if err != nil {
			return fmt.Errorf("failed to recompute data after period: %v", err)
		}

		return s.datas.Store(datas[len(datas)-1])
	}

	// Try to find the next data after the end date on another day
	nextDailyData := s.datas.FindNext(sensorID, end)

	if nextDailyData == nil {
		return nil
	}

	nextIdx := nextDailyData.getFirstIdx()

	// Stop process if next data has no index (so its a value)
	if nextIdx == nil {
		return nil
	}

	// Update the first entry of the next data with the last index from our period
	// and store the updated data
	err := nextDailyData.UpdateFirst(lastDatum.Index, nil, nextDailyData.UnitPrice, nextDailyData.Date)

	if err != nil {
		return fmt.Errorf("failed to update data after period: %v", err)
	}

	return s.datas.Store(nextDailyData)
}

// NewService creates a dataCRUD service with necessary dependencies.
func NewService(datas Repository) Service {
	return &service{
		datas: datas,
	}
}
