	// Get the DailyData before and after the first and last date
	prevDBData := s.datas.FindPrev(first.SensorID, first.Date.Time)
	nextDBData := s.datas.FindNext(first.SensorID, last.Date.Time)

	if prevDBData != nil {
		dbDatasSlice = append(dbDatasSlice, prevDBData)
	}

	if nextDBData != nil {
		dbDatasSlice = append(dbDatasSlice, nextDBData)
	}

	// Sort dbDatas by date
	var dates []time.Time
	dbDatas := make(map[string]*DailyData)
	for _, _dbData := range dbDatasSlice {
		dbDatas[_dbData.Date.UTC().String()] = _dbData
		dates = append(dates, _dbData.Date)
	}
	sortDates(dates)

	for _, raw := range rawDatas {
		if err := s.processRawData(raw, dbDatas, &dates); err != nil {
			return err
		}
	}

	// Ensure next values are properly computed after all data is stored
	return s.RecomputeNextValue(first.SensorID, first.Date.Time, last.Date.Time)
}

// processRawData processes a single raw data entry and updates the database accordingly
func (s *service) processRawData(raw *RawData, dbDatas map[string]*DailyData, dates *[]time.Time) error {
	day := raw.Date.Truncate(24 * time.Hour)
	current := dbDatas[day.String()]

	var isNew bool // Tell if the current DailyData just has been created

	if current == nil {
		current = &DailyData{
			SensorID: raw.SensorID,
			Date:     day,
		}
		isNew = true
		dbDatas[day.String()] = current
		*dates = append(*dates, day)
		sortDates(*dates)
	}

	// Handle value-based raw data
	if raw.Value != nil {
		current.AddUpdate(raw.Value, nil, nil, nil, raw.UnitPrice, raw.Date.Time, raw.Threshold, raw.Coef)
		return s.datas.Store(current)
	} 

	// Handle index-based raw data
	if raw.Index != nil {
		return s.processIndexRawData(raw, current, isNew, dbDatas, *dates, day)
	}

	return fmt.Errorf("there is no value or index for sensor %s for date %v", raw.SensorID, raw.Date.Time)
}

// processIndexRawData handles the logic for processing index-based raw data
func (s *service) processIndexRawData(raw *RawData, current *DailyData, isNew bool, 
	dbDatas map[string]*DailyData, dates []time.Time, day time.Time) error {

	var lastIdx *float64
	prevDate, nextDate := prevNextDates(dates, day)

	// Handle newly created daily data
	if isNew {
		if prevDate != nil {
			prevData := dbDatas[prevDate.String()]
			if prevData != nil {
				lastIdx = prevData.Index
			}
		}

		current.AddUpdate(nil, raw.Index, lastIdx, raw.Factor, raw.UnitPrice, raw.Date.Time, raw.Threshold, raw.Coef)
		if err := s.datas.Store(current); err != nil {
			return err
		}

		// Update next data if exists
		if nextDate != nil {
			return s.updateNextDataWithIndex(dbDatas, nextDate, raw)
		}
		return nil
	}

	// Handle existing daily data
	firstDT, lastDT := current.FirstLastDT()

	// If this data is at or before the first existing entry for the day
	if raw.Date.Before(firstDT) || raw.Date.Equal(firstDT) {
		if prevDate != nil {
			prevData := dbDatas[prevDate.String()]
			if prevData != nil {
				lastIdx = prevData.Index
			}
		}
	}

	// If this data is at or after the last existing entry for the day
	if raw.Date.After(lastDT) || raw.Date.Equal(lastDT) {
		if nextDate != nil {
			if err := s.updateNextDataWithIndex(dbDatas, nextDate, raw); err != nil {
				return err
			}
		}
	}

	if err := current.AddUpdate(raw.Value, raw.Index, lastIdx, raw.Factor, raw.UnitPrice, 
		raw.Date.Time, raw.Threshold, raw.Coef); err != nil {
		return err
	}

	return s.datas.Store(current)
}

// updateNextDataWithIndex updates the first entry of the next day with the current index
func (s *service) updateNextDataWithIndex(dbDatas map[string]*DailyData, nextDate *time.Time, raw *RawData) error {
	nextData := dbDatas[nextDate.String()]
	if err := nextData.UpdateFirst(raw.Index, raw.Factor, raw.UnitPrice, raw.Date.Time); err != nil {
		return err
	}
	return s.datas.Store(nextData)
}
